create table if not exists public.workflow_versions (id uuid primary key default gen_random_uuid(), workflow_key text not null, version int not null, execution_graph jsonb not null, created_at timestamptz not null default now(), unique(workflow_key, version));
create table if not exists public.workflow_transitions (id uuid primary key default gen_random_uuid(), run_id uuid not null references public.workflow_runs(id), from_state text not null, to_state text not null, created_at timestamptz not null default now());
create table if not exists public.workflow_logs (id uuid primary key default gen_random_uuid(), run_id uuid not null references public.workflow_runs(id), step_key text, message text not null, created_at timestamptz not null default now());
create table if not exists public.workflow_snapshots (id uuid primary key default gen_random_uuid(), run_id uuid not null references public.workflow_runs(id), execution_context jsonb not null default '{}', step_results jsonb not null default '{}', created_at timestamptz not null default now());
create table if not exists public.workflow_compensations (id uuid primary key default gen_random_uuid(), run_id uuid not null references public.workflow_runs(id), failed_step text not null, compensation_chain jsonb not null default '[]', created_at timestamptz not null default now());
create table if not exists public.workflow_templates (id uuid primary key default gen_random_uuid(), tenant_id text not null, template_key text not null, workflow_definition jsonb not null, created_at timestamptz not null default now());
create index if not exists idx_workflow_runs_tenant_state on public.workflow_runs(tenant_id, state);
create index if not exists idx_workflow_steps_run_state on public.workflow_steps(run_id, state);
